#include <bits/stdc++.h>
using namespace std;
const int N=1005;
vector<int> g[N];
int n,m,vis[N],a[N],vis2[N],vis3[N][N],ans;
void dfs(int u)
{
	if(vis[u]) return ;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		dfs(v);
		vis[u]=max(vis[u],vis[v]+1);
	}
	return ;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int k;
		cin>>k;
		memset(vis2,0,sizeof(vis2));
		for(int j=1;j<=k;j++)
		{
			cin>>a[j];
			vis2[a[j]]=1;
		}
		for(int j2=a[1];j2<=a[k];j2++)
		{
			if(vis2[j2]) continue;
			for(int j=1;j<=k;j++)
			{
				if(!vis3[a[j]][j2]) g[a[j]].push_back(j2);
				vis3[a[j]][j2]=1;
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		if(!vis[i]) dfs(i);
		ans=max(ans,vis[i]);
	}
	cout<<ans+1;
	return 0;
}
